import json

import yaml

from prompty.model import TurnStartPayload


def test_load_json_turnstartpayload():
    json_data = r"""
    {
      "agent": "weather-agent",
      "maxIterations": 10
    }
    """
    data = json.loads(json_data, strict=False)
    instance = TurnStartPayload.load(data)
    assert instance is not None
    assert instance.agent == "weather-agent"
    assert instance.max_iterations == 10


def test_load_yaml_turnstartpayload():
    yaml_data = r"""
    agent: weather-agent
    maxIterations: 10

    """
    data = yaml.load(yaml_data, Loader=yaml.FullLoader)
    instance = TurnStartPayload.load(data)
    assert instance is not None
    assert instance.agent == "weather-agent"
    assert instance.max_iterations == 10


def test_roundtrip_json_turnstartpayload():
    """Test that load -> save -> load produces equivalent data."""
    json_data = r"""
    {
      "agent": "weather-agent",
      "maxIterations": 10
    }
    """
    original_data = json.loads(json_data, strict=False)
    instance = TurnStartPayload.load(original_data)
    saved_data = instance.save()
    reloaded = TurnStartPayload.load(saved_data)
    assert reloaded is not None
    assert reloaded.agent == "weather-agent"
    assert reloaded.max_iterations == 10


